diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9f034aba874a..e40127fdd56e 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -2897,16 +2897,107 @@ Instruction *InstCombinerImpl::foldICmpSubConstant(ICmpInst &Cmp,

 /// Fold icmp (add X, Y), C.
 Instruction *InstCombinerImpl::foldICmpAddConstant(ICmpInst &Cmp,
-                                                   BinaryOperator *Add,
-                                                   const APInt &C) {
+                                                    BinaryOperator *Add,
+                                                    const APInt &C) {
   Value *Y = Add->getOperand(1);
+  Value *X = Add->getOperand(0);
+
+  // Try to fold icmp Pred (add (ext i1 A), (ext i1 B)), C.
+  Value *A = nullptr, *B = nullptr;
+  bool AIsSExt, BIsSExt;
+  {
+    auto MatchExt = [&](Value *&V, bool &IsSExt) {
+      if (match(V, m_ZExt(m_Value(V))) &&
+          V->getType()->isIntOrIntVectorTy(1)) {
+        IsSExt = false;
+        return true;
+      }
+      if (match(V, m_SExt(m_Value(V))) &&
+          V->getType()->isIntOrIntVectorTy(1)) {
+        IsSExt = true;
+        return true;
+      }
+      return false;
+    };
+
+    Value *AV = X, *BV = Y;
+    if (MatchExt(AV, AIsSExt) && MatchExt(BV, BIsSExt)) {
+      A = AV;
+      B = BV;
+    } else if (MatchExt(AV = Y, AIsSExt) && MatchExt(BV = X, BIsSExt)) {
+      A = AV;
+      B = BV;
+    }
+  }
+
+  if (A && B) {
+    // Compute the three or four possible sum values.
+    APInt ExtA1 = APInt(C.getBitWidth(), AIsSExt ? -1 : 1);
+    APInt ExtB1 = APInt(C.getBitWidth(), BIsSExt ? -1 : 1);
+    APInt V00 = APInt(C.getBitWidth(), 0);
+    APInt V01 = ExtB1;                     // A=0, B=1
+    APInt V10 = ExtA1;                     // A=1, B=0
+    APInt V11 = ExtA1 + ExtB1;             // A=1, B=1
+
+    auto Eval = [&](const APInt &V) -> bool {
+      switch (Cmp.getPredicate()) {
+      case ICmpInst::ICMP_EQ:  return V.eq(C);
+      case ICmpInst::ICMP_NE:  return V.ne(C);
+      case ICmpInst::ICMP_ULT: return V.ult(C);
+      case ICmpInst::ICMP_UGT: return V.ugt(C);
+      case ICmpInst::ICMP_SLT: return V.slt(C);
+      case ICmpInst::ICMP_SGT: return V.sgt(C);
+      // ULE/UGE/SLE/SGE are canonicalized to ULT/UGT/SLT/SGT.
+      default: return false;
+      }
+    };
+
+    bool T00 = Eval(V00), T01 = Eval(V01), T10 = Eval(V10), T11 = Eval(V11);
+    int NumTrue = (int)T00 + (int)T01 + (int)T10 + (int)T11;
+
+    // If all or none satisfy the predicate, return constant.
+    if (NumTrue == 4)
+      return replaceInstUsesWith(Cmp, Builder.getTrue());
+    if (NumTrue == 0)
+      return replaceInstUsesWith(Cmp, Builder.getFalse());
+
+    // Build boolean expression from satisfying (A,B) pairs.
+    auto GetCond = [&](bool AVal, bool BVal) -> Value * {
+      Value *ACond = AVal ? A : Builder.CreateNot(A);
+      Value *BCond = BVal ? B : Builder.CreateNot(B);
+      return Builder.CreateAnd(ACond, BCond);
+    };
+
+    Value *Result = nullptr;
+    if (T00) Result = GetCond(false, false);
+    if (T01) {
+      Value *Term = GetCond(false, true);
+      Result = Result ? Builder.CreateOr(Result, Term) : Term;
+    }
+    if (T10) {
+      Value *Term = GetCond(true, false);
+      Result = Result ? Builder.CreateOr(Result, Term) : Term;
+    }
+    if (T11) {
+      Value *Term = GetCond(true, true);
+      Result = Result ? Builder.CreateOr(Result, Term) : Term;
+    }
+
+    // For eq/ne cases producing a single instruction, we leave it to
+    // foldICmpBinOpEqualityWithConstant which produces simpler output.
+    // For non-equality, check one-use.
+    if (Cmp.isEquality())
+      return nullptr;
+
+    if (!Add->hasOneUse())
+      return nullptr;
+
+    return replaceInstUsesWith(Cmp, Result);
+  }
+
   const APInt *C2;
   if (Cmp.isEquality() || !match(Y, m_APInt(C2)))
     return nullptr;
-
-  // Fold icmp pred (add X, C2), C.
-  Value *X = Add->getOperand(0);
-  Type *Ty = Add->getType();
   const CmpInst::Predicate Pred = Cmp.getPredicate();

   // If the add does not wrap, we can always adjust the compare by subtracting
@@ -3344,6 +3435,133 @@ Instruction *InstCombinerImpl::foldICmpBinOpEqualityWithConstant(
         Neg->takeName(BO);
         return new ICmpInst(Pred, BOp0, Neg);
       }
+    } else {
+      // icmp eq/ne (add (ext i1 A), (ext i1 B)), C --> boolean logic
+      Value *A, *B;
+      bool AIsSExt, BIsSExt;
+      if (match(BOp0, m_SExt(m_Value(A))) &&
+          match(BOp1, m_SExt(m_Value(B))) &&
+          A->getType()->isIntOrIntVectorTy(1) &&
+          B->getType()->isIntOrIntVectorTy(1)) {
+        AIsSExt = true;
+        BIsSExt = true;
+      } else if (match(BOp0, m_ZExt(m_Value(A))) &&
+                 match(BOp1, m_ZExt(m_Value(B))) &&
+                 A->getType()->isIntOrIntVectorTy(1) &&
+                 B->getType()->isIntOrIntVectorTy(1)) {
+        AIsSExt = false;
+        BIsSExt = false;
+      } else if (match(BOp0, m_SExt(m_Value(A))) &&
+                 match(BOp1, m_ZExt(m_Value(B))) &&
+                 A->getType()->isIntOrIntVectorTy(1) &&
+                 B->getType()->isIntOrIntVectorTy(1)) {
+        AIsSExt = true;
+        BIsSExt = false;
+      } else if (match(BOp0, m_ZExt(m_Value(A))) &&
+                 match(BOp1, m_SExt(m_Value(B))) &&
+                 A->getType()->isIntOrIntVectorTy(1) &&
+                 B->getType()->isIntOrIntVectorTy(1)) {
+        AIsSExt = false;
+        BIsSExt = true;
+      } else {
+        break;
+      }
+
+      bool IsEQ = Pred == ICmpInst::ICMP_EQ;
+      bool IsNE = Pred == ICmpInst::ICMP_NE;
+      if (!IsEQ && !IsNE)
+        break;
+
+      // For NE cases producing a two-instruction sequence (not(xor/and)),
+      // require the add to have one use so we can eliminate it.
+      if (IsNE && !BO->hasOneUse())
+        break;
+
+      // Helper to create "not" of a value.
+      auto CreateNot = [&](Value *V) -> Value * {
+        return Builder.CreateNot(V);
+      };
+
+      if (AIsSExt == BIsSExt) {
+        // Both are the same kind of extension.
+        // Possible sums:
+        //   zext+zext: 0, 1, 2
+        //   sext+sext: 0, -1, -2
+        APInt One = APInt(C.getBitWidth(), AIsSExt ? -1 : 1);
+        APInt Two = APInt(C.getBitWidth(), AIsSExt ? -2 : 2);
+        if (IsEQ) {
+          if (C == One)
+            return BinaryOperator::CreateXor(A, B);
+          if (C == Two)
+            return BinaryOperator::CreateAnd(A, B);
+          // Any other C value is impossible for these extensions.
+          return replaceInstUsesWith(Cmp, Builder.getFalse());
+        } else {
+          // IsNE
+          if (C == One)
+            return BinaryOperator::CreateXor(Builder.CreateXor(A, B),
+                                             ConstantInt::get(A->getType(), 1));
+          // C == 0 handled by earlier else-if block.
+          if (C == Two)
+            return BinaryOperator::CreateXor(Builder.CreateAnd(A, B),
+                                             ConstantInt::get(A->getType(), 1));
+          // Any other C value is always true.
+          return replaceInstUsesWith(Cmp, Builder.getTrue());
+        }
+      } else {
+        // Mixed sext and zext. Possible sums: -1, 0, 1.
+        // Let A be the sext operand, B be the zext operand.
+        if (AIsSExt) {
+          // A is sext, B is zext. Sum = {-1 (A=1,B=0), 0 (A=0,B=0 or A=1,B=1), 1 (A=0,B=1)}
+          // C = -1: A & !B
+          // C = 0:  !(A xor B)
+          // C = 1:  !A & B
+          APInt MinusOne = APInt::getAllOnes(C.getBitWidth());
+          if (IsEQ) {
+            if (C == MinusOne)
+              return BinaryOperator::CreateAnd(A, Builder.CreateNot(B));
+            if (C.isZero())
+              return BinaryOperator::CreateXor(
+                  Builder.CreateXor(A, B),
+                  ConstantInt::get(A->getType(), 1));
+            if (C.isOne())
+              return BinaryOperator::CreateAnd(Builder.CreateNot(A), B);
+            return replaceInstUsesWith(Cmp, Builder.getFalse());
+          } else {
+            // IsNE
+            if (C == MinusOne)
+              return BinaryOperator::CreateOr(Builder.CreateNot(A), B);
+            if (C.isZero())
+              return BinaryOperator::CreateXor(A, B);
+            if (C.isOne())
+              return BinaryOperator::CreateOr(A, Builder.CreateNot(B));
+            return replaceInstUsesWith(Cmp, Builder.getTrue());
+          }
+        } else {
+          // B is sext, A is zext. Sum = {1 (A=1,B=0), 0 (A=0,B=0 or A=1,B=1), -1 (A=0,B=1)}
+          APInt MinusOne = APInt::getAllOnes(C.getBitWidth());
+          if (IsEQ) {
+            if (C == MinusOne)
+              return BinaryOperator::CreateAnd(Builder.CreateNot(A), B);
+            if (C.isZero())
+              return BinaryOperator::CreateXor(
+                  Builder.CreateXor(A, B),
+                  ConstantInt::get(A->getType(), 1));
+            if (C.isOne())
+              return BinaryOperator::CreateAnd(A, Builder.CreateNot(B));
+            return replaceInstUsesWith(Cmp, Builder.getFalse());
+          } else {
+            // IsNE
+            if (C == MinusOne)
+              return BinaryOperator::CreateOr(A, Builder.CreateNot(B));
+            if (C.isZero())
+              return BinaryOperator::CreateXor(A, B);
+            if (C.isOne())
+              return BinaryOperator::CreateOr(Builder.CreateNot(A), B);
+            return replaceInstUsesWith(Cmp, Builder.getTrue());
+          }
+        }
+      }
     }
     break;
   }

